const prep = $item(0).$node["Prepare Input"].json;
const item = $input.first();
const b64 = item.binary?.fileData?.data;
if (!b64) { return [{ json: { batchId: prep.batchId, sourceFileId: prep.sourceFileId, error: "file_binary_missing", rows: [], aiConfig: prep.aiConfig || {}, mode: prep.mode || "BENCHMARK" } }]; }
return [{ json: { batchId: prep.batchId, sourceFileId: prep.sourceFileId, fileUrl: prep.fileUrl, objectKey: prep.objectKey || null, sourceType: prep.sourceType || null, mode: prep.mode || "BENCHMARK", aiConfig: prep.aiConfig || {}, base64Content: b64 } }];

const prep = $item(0).$node["Prepare Input"].json;
const response = $input.first().json;
let error = null;
let ocrRawText = "";
try {
  const apiError = response.responses?.[0]?.error;
  if (apiError) { error = apiError.message || "vision_api_error"; }
  else { ocrRawText = (response.responses?.[0]?.fullTextAnnotation?.text || response.responses?.[0]?.textAnnotations?.[0]?.description || "").trim(); if (!ocrRawText) error = "ocr_empty_text"; }
} catch (err) { error = err?.message || "ocr_parse_exception"; }
return [{ json: { batchId: prep.batchId, sourceFileId: prep.sourceFileId, fileUrl: prep.fileUrl, objectKey: prep.objectKey || null, sourceType: prep.sourceType || null, mode: prep.mode || "PRODUCTION", aiConfig: prep.aiConfig || {}, ocrRawText, error } }];

const input = $input.first().json;
const activeConfig = input.aiConfig && typeof input.aiConfig === "object" ? input.aiConfig : {};
const startedAt = Date.now();
const MODEL_MATRIX = ["openai/gpt-4o-mini","google/gemini-2.5-flash","google/gemini-2.5-flash-lite","deepseek/deepseek-v3.2","minimax/minimax-m2.7","x-ai/grok-4.1-fast"];

const PROMPT_LIBRARY = {
  "prod-v1": {
    "label": "Balanced Extractor",
    "systemPrompt": "Sen deterministik bir OCR randevu ayrıştırıcısısın. Sadece geçerli JSON üret. Şema tam olarak {\"rows\":[...]} olmalı. Her row alanları: rowIndex, customerName, customerPhoneRaw, appointmentDate, startTime, endTime, durationMinutes, serviceNameRaw, staffNameRaw, priceRaw, notesRaw, confidence. Türkçe karakterleri koru. Müşteri ismini okunabilir olacak şekilde düzeltebilirsin ama emin değilsen OCR haline yakın kal. Hizmet adlarını mantıklı biçimde normalize et. Kalıcı Oje, Tüm Vücut Lazer, Kaş Alımı, Lazer, Ağda, Pedikür, Manikür, Jel Güçlendirme gibi normalize et. Hatırlat, geldi, iptal, ödedi, aransın gibi notları notesRaw alanına taşı. Birden fazla hizmet varsa virgülle ayır. Saatleri HH:MM formatına çevir. Personel adı açıkça yoksa staffNameRaw null olsun. Satır uydurma, komşu satırdan hizmet taşıma, telefon uydurma yapma."
  },
  "prod-v2": {
    "label": "Conservative Extractor",
    "systemPrompt": "Sen çok konservatif çalışan bir OCR randevu ayrıştırıcısısın. Sadece JSON üret: {\"rows\":[...]}. Emin olmadığın hiçbir değeri tahmin etme; null bırak. Hizmeti yalnızca güçlü sinyal varsa normalize et. TV lazer = Tüm Vücut Lazer. kaş, kas, kaş- = Kaş Alımı. kal je, kalıcı oje = Kalıcı Oje. ağda varyasyonları = Ağda. lazer, lezer, lover, lace = Lazer. pedikur = Pedikür. manikur = Manikür. jel güçlendirme varyasyonlarını Jel Güçlendirme yap. Hatırlat ve benzeri notlar notesRaw alanına gitmeli. serviceNameRaw alanına not veya kişi unvanı koyma. Çıktıda sadece geçerli JSON olsun."
  },
  "prod-v3": {
    "label": "Line Grouping Extractor",
    "systemPrompt": "Sen el yazısı salon defterlerinden randevu çıkaran bir ayrıştırıcısın. Önce zamanı tespit et, sonra o zamanın altındaki yakın OCR parçalarını aynı randevuda grupla. Sonraki saat başladığında yeni randevu başlar. Çıktı sadece JSON olmalı: {\"rows\":[...]}. customerName müşterinin adı olmalı. serviceNameRaw hizmetlerin Türkçe normalize edilmiş gösterimi olmalı. staffNameRaw yalnızca gerçekten yazıyorsa dolu olmalı. Telefonu görüldüğü gibi koru; sadece bariz boşluk gürültüsünü temizleyebilirsin. Saat formatını HH:MM yap. Kaş ile ilgili ifadeleri Kaş Alımı, TV lazeri Tüm Vücut Lazer olarak normalize et. Birden fazla hizmeti virgülle ayır. Notları notesRaw alanına taşı. Hiçbir açıklama ekleme."
  },
  "prod-v4": {
    "label": "Turkish Fidelity Extractor",
    "systemPrompt": "Sen Türkiye salonları için optimize edilmiş bir OCR post-processor modelisin. Türkçe karakterleri koru: Ç, Ğ, İ, Ö, Ş, Ü ve küçük halleri. Çıktı yalnızca JSON olacak: {\"rows\":[...]}. Her randevu satırı için müşteri adı, telefon, tarih, saat, hizmet, not alanlarını çıkar. E2gi gibi OCR hatalarını Ezgi gibi okuyorsan düzeltebilirsin; ancak emin değilsen olduğu gibi bırak. Hanım, bey, hnm gibi unvanları customerName içinde tutabilirsin, serviceNameRaw içine taşıma. Demet hanım gibi isimlerde hanım kelimesini hizmet gibi yorumlama. TV lazeri tek hizmet olarak Tüm Vücut Lazer yap; ayrıca ekstra Lazer ekleme. Hatırlat gibi operasyon notlarını notesRaw alanına koy. JSON dışında tek karakter bile üretme."
  },
  "prod-v5": {
    "label": "Strict JSON Extractor",
    "systemPrompt": "Deterministik çalış. Yalnızca geçerli JSON üret: {\"rows\":[...]}. Her row alanı şu sırayla bulunmalı: rowIndex, customerName, customerPhoneRaw, appointmentDate, startTime, endTime, durationMinutes, serviceNameRaw, staffNameRaw, priceRaw, notesRaw, confidence. Boş alanlara null yaz. Telefon uydurma yok, saat uydurma yok, satır uydurma yok. Tek bir randevuyu başka randevu ile birleştirme. Service normalization sözlüğü: Kalıcı Oje, Tüm Vücut Lazer, Kaş Alımı, Lazer, Ağda, Pedikür, Manikür, Jel Güçlendirme. NotesRaw için örnek notlar: hatırlat, geldi, iptal, ödedi, aransın. Türkçe karakterleri koru. JSON dışında hiçbir şey yazma."
  }
};
function t(v){return typeof v==='string'?v.trim():''}
function nt(v){const x=t(v);return x||null}
function nTime(v){const x=t(v);if(!x)return null;let m=x.match(/^(\d{1,2})[:.](\d{2})$/);if(m){const h=+m[1],mm=+m[2];if(h>=0&&h<=23&&mm>=0&&mm<=59)return String(h).padStart(2,'0')+':'+String(mm).padStart(2,'0')}m=x.match(/^(\d{2})(\d{2})$/);if(m){const h=+m[1],mm=+m[2];if(h>=0&&h<=23&&mm>=0&&mm<=59)return String(h).padStart(2,'0')+':'+String(mm).padStart(2,'0')}return null}
function nDate(v){const x=t(v);if(!x)return null;let m=x.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{2,4})$/);if(m){let y=+m[3];if(y<100)y+=2000;return String(m[1]).padStart(2,'0')+'.'+String(m[2]).padStart(2,'0')+'.'+String(y).padStart(4,'0')}if(/^(\d{4})-(\d{2})-(\d{2})$/.test(x))return x;return null}
function nNum(v){if(v===null||v===undefined||v==='')return null;const n=Number(String(v).replace(',', '.'));return Number.isFinite(n)?n:null}
function content(j){const m=j?.choices?.[0]?.message?.content;if(typeof m==='string')return m.trim();if(Array.isArray(m))return m.map((p)=>typeof p==='string'?p:(p&&typeof p.text==='string'?p.text:'')).join('\n').trim();return ''}
function extractJson(raw){const s=t(raw);if(!s)throw new Error('llm_empty_output');try{return JSON.parse(s)}catch(e){const fence=String.fromCharCode(96).repeat(3);const fenced=s.match(new RegExp(fence+'(?:json)?\\s*([\\s\\S]*?)'+fence,'i'));if(fenced)return JSON.parse(fenced[1].trim());const a=s.indexOf('{');const b=s.lastIndexOf('}');if(a!==-1&&b>a)return JSON.parse(s.slice(a,b+1));throw e}}
function normRows(payload){const rows=Array.isArray(payload)?payload:(Array.isArray(payload?.rows)?payload.rows:[]);return rows.map((r,i)=>({rowIndex:Number(r?.rowIndex)>0?Number(r.rowIndex):i+1,customerName:nt(r?.customerName),customerPhoneRaw:nt(r?.customerPhoneRaw),appointmentDate:nDate(r?.appointmentDate||r?.date),startTime:nTime(r?.startTime||r?.time),endTime:nTime(r?.endTime),durationMinutes:nNum(r?.durationMinutes),serviceNameRaw:nt(r?.serviceNameRaw||r?.servicesNormalized||r?.service),staffNameRaw:nt(r?.staffNameRaw||r?.staff),priceRaw:nNum(r?.priceRaw),notesRaw:nt(r?.notesRaw||r?.note),confidence:(()=>{const v=Number(r?.confidence);if(!Number.isFinite(v))return 0.5;return Math.max(0,Math.min(1,v))})()})).filter((r)=>r.appointmentDate||r.startTime||r.customerName||r.serviceNameRaw||r.notesRaw)}
function userPrompt(ocrRawText){return ['Aşağıdaki OCR metnini verilen JSON şemasına göre ayrıştır.','Sadece JSON üret.','OCR METNI:',ocrRawText].join('\n\n')}
async function callOpenRouter(input){const apiKey=String(process.env.OPENROUTER_API_KEY||'').trim();if(!apiKey)throw new Error('openrouter_api_key_missing');const res=await fetch('https://openrouter.ai/api/v1/chat/completions',{method:'POST',headers:{'content-type':'application/json',authorization:'Bearer '+apiKey,'http-referer':String(process.env.OPENROUTER_REFERER||'https://app.berkai.shop'),'x-title':'Kedy Import OCR'},body:JSON.stringify({model:input.model,temperature:0,max_tokens:4000,messages:[{role:'system',content:input.systemPrompt},{role:'user',content:userPrompt(input.ocrRawText)}]})});const txt=await res.text();let json=null;try{json=txt?JSON.parse(txt):null}catch(e){json=null}if(!res.ok)throw new Error('openrouter_http_'+res.status+':'+(json?.error?.message||txt||'request_failed'));const rawOutputText=content(json);const parsedRows=normRows(extractJson(rawOutputText));return {provider:'openrouter',model:input.model,rawOutputText,parsedRows}}

async function runWithConcurrency(items, limit, worker) { const results = new Array(items.length); let cursor = 0; async function next(){ const index = cursor; cursor += 1; if (index >= items.length) return; results[index] = await worker(items[index], index); return next(); } await Promise.all(Array.from({ length: Math.max(1, Math.min(limit, items.length)) }, () => next())); return results; }
if (input.error) { return [{ json: { ...input, rows: [], candidates: [], audit: { ocrProvider: "google-vision", ocrModel: "DOCUMENT_TEXT_DETECTION", ocrRawText: input.ocrRawText || "", activeConfigSnapshot: activeConfig, metrics: { durationMs: Date.now() - startedAt, candidateCount: 0, successCount: 0, failureCount: 0 } } } }]; }
const promptEntries = Object.entries(PROMPT_LIBRARY).map(([promptVersion, prompt]) => ({ promptVersion, promptLabel: prompt.label, systemPrompt: prompt.systemPrompt }));
const matrix = []; for (const model of MODEL_MATRIX) { for (const prompt of promptEntries) matrix.push({ model, ...prompt }); }
try {
  const candidates = await runWithConcurrency(matrix, 4, async (item) => { try { const result = await callOpenRouter({ model: item.model, systemPrompt: item.systemPrompt, ocrRawText: input.ocrRawText || "" }); return { provider: result.provider, model: result.model, promptVersion: item.promptVersion, promptLabel: item.promptLabel, rawOutputText: result.rawOutputText, parsedRows: result.parsedRows }; } catch (err) { return { provider: "openrouter", model: item.model, promptVersion: item.promptVersion, promptLabel: item.promptLabel, rawOutputText: "ERROR: " + (err?.message || "unknown_error"), parsedRows: [] }; } });
  const successCount = candidates.filter((candidate) => Array.isArray(candidate.parsedRows) && candidate.parsedRows.length > 0).length;
  const failureCount = candidates.length - successCount;
  return [{ json: { ...input, rows: [], candidates, audit: { ocrProvider: "google-vision", ocrModel: "DOCUMENT_TEXT_DETECTION", ocrRawText: input.ocrRawText || "", activeConfigSnapshot: activeConfig, metrics: { durationMs: Date.now() - startedAt, candidateCount: candidates.length, successCount, failureCount, modelCount: MODEL_MATRIX.length, promptCount: promptEntries.length } }, error: null } }];
} catch (err) {
  return [{ json: { ...input, rows: [], candidates: [], audit: { ocrProvider: "google-vision", ocrModel: "DOCUMENT_TEXT_DETECTION", ocrRawText: input.ocrRawText || "", activeConfigSnapshot: activeConfig, metrics: { durationMs: Date.now() - startedAt, candidateCount: 0 } }, error: err?.message || "benchmark_matrix_failed" } }];
}
